Write Composio.dev connector for ACC v2:
javascript
// cloud/integrations/composio.js
// Composio.dev connector for ACC v2 - unified API for 250+ tools

const axios = require('axios');

const BASE_URL = 'https://backend.composio.dev/api/v1';

function getApiKey() {
  return process.env.COMPOSIO_API_KEY;
}

function enabled() {
  const key = getApiKey();
  return !!key && key.length > 0;
}

async function checkHealth() {
  if (!enabled()) {
    return { status: 'disabled', message: 'COMPOSIO_API_KEY not set' };
  }
  try {
    const res = await axios.get(`${BASE_URL}/apps`, {
      headers: { Authorization: `Bearer ${getApiKey()}` },
      timeout: 10000
    });
    return { status: 'ok', appsCount: res.data?.length || 0 };
  } catch (err) {
    return { status: 'error', message: err.message };
  }
}

async function listApps() {
  if (!enabled()) throw new Error('Composio not enabled');
  const res = await axios.get(`${BASE_URL}/apps`, {
    headers: { Authorization: `Bearer ${getApiKey()}` }
  });
  return res.data;
}

async function getActions(appName) {
  if (!enabled()) throw new Error('Composio not enabled');
  const res = await axios.get(`${BASE_URL}/apps/${appName}/actions`, {
    headers: { Authorization: `Bearer ${getApiKey()}` }
  });
  return res.data;
}

async function executeAction(appName, actionName, params = {}) {
  if (!enabled()) throw new Error('Composio not enabled');
  const res = await axios.post(
    `${BASE_URL}/actions/${appName}/${actionName}/execute`,
    params,
    {
      headers: {
        Authorization: `Bearer ${getApiKey()}`,
        'Content-Type': 'application/json'
      }
    }
  );
  return res.data;
}

async function sendTaskFromACC(accTask) {
  // Expected accTask format: { instruction: "gmail:sendEmail to:test@test.com subject:Hello body:World" }
  if (!accTask || !accTask.instruction) {
    throw new Error('Invalid ACC task: missing instruction');
  }

  const instruction = accTask.instruction;
  // Parse: "appName:actionName param1:value1 param2:value2"
  const match = instruction.match(/^(\w+):(\w+)\s+(.+)$/);
  if (!match) {
    throw new Error(`Cannot parse instruction: ${instruction}. Expected format: appName:actionName key:val key2:val2`);
  }

  const appName = match[1];
  const actionName = match[2];
  const paramsStr = match[3];

  // Parse key:value pairs
  const params = {};
  const paramRegex = /(\w+):([^\s]+)/g;
  let paramMatch;
  while ((paramMatch = paramRegex.exec(paramsStr)) !== null) {
    params[paramMatch[1]] = paramMatch[2];
  }

  return await executeAction(appName, actionName, params);
}

module.exports = {
  enabled,
  checkHealth,
  listApps,
  getActions,
  executeAction,
  sendTaskFromACC
};


